function openURLInNewWindow(url) {
    window.open(url, "_blank")
}

function giftImgURL(index) {
    openURLInNewWindow(gift_img_URLs[index])
}

function giftButtonURL(index) {
    openURLInNewWindow(gift_button_URLs[index])
}
